def solve(nums: Array[Long]): Long = {
    def isPrime(n: Int): Boolean = {
        if (n <= 1) false
        else if (n == 2) true
        else if (n % 2 == 0) false
        else {
            var i = 3
            val sqrtN = math.sqrt(n).toInt
            while (i <= sqrtN) {
                if (n % i == 0) return false
                i += 2
            }
            true
        }
    }

    var sumA = 0L
    var sumB = 0L
    for (i <- nums.indices) {
        if (isPrime(i)) {
            sumA += nums(i)
        } else {
            sumB += nums(i)
        }
    }
    math.abs(sumA - sumB)
}
